function slug(name) {
  return name.replace(/([a-z0-9])([A-Z])/g, '$1-$2').toLowerCase()
}

function signatureFor(name) {
  const file = path.join(coreDist, name, 'index.d.ts')
  return fs.readFileSync(file, 'utf8').replace(/\/# sourceMappingURL=.*\n?/g, '').trim()
}

function pageMeta(name) {
  return {
    name,
    slug: slug(name),
    description: hookDescriptions[name],
    signature: signatureFor(name),
    browserOnly: browserOnly.has(name),
    importCode: `import { ${name} } from '@kamod-ch/hooks'`,
    related: (related[name] ?? []).map((item) => ({ name: item, href: `/hooks/${slug(item)}` })),
  }
}

function write(file, content) {
  fs.mkdirSync(path.dirname(file), { recursive: true })
  fs.writeFileSync(file, content)
}

const hookNames = groups.flatMap((group) => group.items)
const metas = hookNames.map(pageMeta)

function demoSource(name) {
  const demos = {
useBoolean: `import { useBoolean } from '@kamod-ch/hooks'\n\nexport default function UseBooleanDemo() {\n  const [value, actions] = useBoolean(false)\n\n  return (\n    <div>\n      <p><strong>Current value:</strong> {String(value)}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={actions.setTrue}>Set true</button>\n        <button type=\"button\" onClick={actions.setFalse}>Set false</button>\n        <button type=\"button\" onClick={actions.toggle}>Toggle</button>\n      </div>\n    </div>\n  )\n}\n`,
useToggle: `import { useToggle } from '@kamod-ch/hooks'\n\nexport default function UseToggleDemo() {\n  const [value, actions] = useToggle('list', 'grid')\n\n  return (\n    <div>\n      <p><strong>Layout:</strong> {value}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={actions.toggle}>Toggle</button>\n        <button type=\"button\" onClick={actions.setLeft}>Set list</button>\n        <button type=\"button\" onClick={actions.setRight}>Set grid</button>\n      </div>\n    </div>\n  )\n}\n`,
useCounter: `import { useCounter } from '@kamod-ch/hooks'\n\nexport default function UseCounterDemo() {\n  const [count, actions] = useCounter(2, { min: 0, max: 10 })\n\n  return (\n    <div>\n      <p><strong>Count:</strong> {count}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => actions.dec()}>-1</button>\n        <button type=\"button\" onClick={() => actions.inc()}>+1</button>\n        <button type=\"button\" onClick={() => actions.set(8)}>Set 8</button>\n        <button type=\"button\" onClick={actions.reset}>Reset</button>\n      </div>\n    </div>\n  )\n}\n`,
useResetState: `import { useResetState } from '@kamod-ch/hooks'\n\nexport default function UseResetStateDemo() {\n  const [message, setMessage, reset] = useResetState('Hello hooks')\n\n  return (\n    <div>\n      <label>\n        Message\n        <input value={message} onInput={(event) => setMessage(event.currentTarget.value)} />\n      </label>\n      <p><strong>Preview:</strong> {message}</p>\n      <button type=\"button\" onClick={reset}>Reset</button>\n    </div>\n  )\n}\n`,
useSetState: `import { useSetState } from '@kamod-ch/hooks'\n\nexport default function UseSetStateDemo() {\n  const [state, setState] = useSetState({ name: 'Ada', role: 'Maintainer' })\n\n  return (\n    <div>\n      <label>\n        Name\n        <input value={state.name} onInput={(event) => setState({ name: event.currentTarget.value })} />\n      </label>\n      <label>\n        Role\n        <input value={state.role} onInput={(event) => setState({ role: event.currentTarget.value })} />\n      </label>\n      <pre>{JSON.stringify(state, null, 2)}</pre>\n    </div>\n  )\n}\n`,
useGetState: `import { useGetState } from '@kamod-ch/hooks'\n\nexport default function UseGetStateDemo() {\n  const [value, setValue, getValue] = useGetState('fresh state')\n\n  return (\n    <div>\n      <label>\n        Value\n        <input value={value} onInput={(event) => setValue(event.currentTarget.value)} />\n      </label>\n      <p><strong>Getter result:</strong> {getValue()}</p>\n    </div>\n  )\n}\n`,
useHistoryTravel: `import { useHistoryTravel } from '@kamod-ch/hooks'\n\nexport default function UseHistoryTravelDemo() {\n  const history = useHistoryTravel('draft')\n\n  return (\n    <div>\n      <label>\n        Value\n        <input value={history.value} onInput={(event) => history.setValue(event.currentTarget.value)} />\n      </label>\n      <p><strong>Back:</strong> {history.backLength} · <strong>Forward:</strong> {history.forwardLength}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={history.back} disabled={!history.backLength}>Undo</button>\n        <button type=\"button\" onClick={history.forward} disabled={!history.forwardLength}>Redo</button>\n        <button type=\"button\" onClick={() => history.reset('draft')}>Reset</button>\n      </div>\n    </div>\n  )\n}\n`,
useSet: `import { useSet } from '@kamod-ch/hooks'\n\nexport default function UseSetDemo() {\n  const [tags, actions] = useSet(['preact'])\n\n  return (\n    <div>\n      <p><strong>Tags:</strong> {[...tags].join(', ') || 'none'}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => actions.add('hooks')}>Add hooks</button>\n        <button type=\"button\" onClick={() => actions.add('docs')}>Add docs</button>\n        <button type=\"button\" onClick={() => actions.remove('preact')}>Remove preact</button>\n        <button type=\"button\" onClick={actions.reset}>Reset</button>\n      </div>\n    </div>\n  )\n}\n`,
useMap: `import { useMap } from '@kamod-ch/hooks'\n\nexport default function UseMapDemo() {\n  const [map, actions] = useMap([['status', 'ready']])\n\n  return (\n    <div>\n      <pre>{JSON.stringify(Object.fromEntries(map), null, 2)}</pre>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => actions.set('status', 'loading')}>Set loading</button>\n        <button type=\"button\" onClick={() => actions.set('theme', 'dark')}>Add theme</button>\n        <button type=\"button\" onClick={() => actions.remove('status')}>Remove status</button>\n        <button type=\"button\" onClick={actions.reset}>Reset</button>\n      </div>\n    </div>\n  )\n}\n`,
useDynamicList: `import { useDynamicList } from '@kamod-ch/hooks'\n\nexport default function UseDynamicListDemo() {\n  const list = useDynamicList(['alpha', 'beta', 'gamma'])\n\n  return (\n    <div>\n      <ol>{list.list.map((item, index) => <li key={list.getKey(index)}>{item}</li>)}</ol>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => list.push('delta')}>Push</button>\n        <button type=\"button\" onClick={() => list.remove(1)}>Remove second</button>\n        <button type=\"button\" onClick={() => list.move(0, list.list.length - 1)}>Move first to last</button>\n        <button type=\"button\" onClick={() => list.resetList(['alpha', 'beta', 'gamma'])}>Reset</button>\n      </div>\n    </div>\n  )\n}\n`,
useSelections: `import { useSelections } from '@kamod-ch/hooks'\n\nconst items = ['Docs', 'Tests', 'Release']\n\nexport default function UseSelectionsDemo() {\n  const selection = useSelections(items)\n\n  return (\n    <div>\n      <fieldset>\n        <legend>Tasks</legend>\n        {items.map((item) => (\n          <label key={item} class=\"demo-option\">\n            <input type=\"checkbox\" checked={selection.isSelected(item)} onInput={() => selection.toggle(item)} />\n            {item}\n          </label>\n        ))}\n      </fieldset>\n      <p><strong>Selected:</strong> {selection.selected.join(', ') || 'none'}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={selection.selectAll}>Select all</button>\n        <button type=\"button\" onClick={selection.clearAll}>Clear</button>\n      </div>\n    </div>\n  )\n}\n`,
useReactive: `import { useReactive } from '@kamod-ch/hooks'\n\nexport default function UseReactiveDemo() {\n  const state = useReactive({ count: 0, nested: { label: 'draft' } })\n\n  return (\n    <div>\n      <pre>{JSON.stringify(state, null, 2)}</pre>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => state.count++}>Increment</button>\n        <button type=\"button\" onClick={() => { state.nested.label = state.nested.label === 'draft' ? 'published' : 'draft' }}>Toggle label</button>\n      </div>\n    </div>\n  )\n}\n`,
useEventTarget: `import { useEventTarget } from '@kamod-ch/hooks'\n\nexport default function UseEventTargetDemo() {\n  const [value, actions] = useEventTarget<string>({ initialValue: 'typed value' })\n\n  return (\n    <div>\n      <input value={value} onInput={(event) => actions.onChange({ target: { value: event.currentTarget.value } })} />\n      <p><strong>Current value:</strong> {value}</p>\n      <button type=\"button\" onClick={actions.reset}>Reset</button>\n    </div>\n  )\n}\n`,
useEventEmitter: `import { useState } from 'preact/hooks'\nimport { useEventEmitter } from '@kamod-ch/hooks'\n\nexport default function UseEventEmitterDemo() {\n  const emitter = useEventEmitter<string>()\n  const [lastMessage, setLastMessage] = useState('nothing yet')\n  emitter.useSubscription((value) => setLastMessage(value))\n\n  return (\n    <div>\n      <p><strong>Last event:</strong> {lastMessage}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => emitter.emit('build started')}>Emit build started</button>\n        <button type=\"button\" onClick={() => emitter.emit('build finished')}>Emit build finished</button>\n      </div>\n    </div>\n  )\n}\n`,
useControllableValue: `import { useState } from 'preact/hooks'\nimport { useControllableValue } from '@kamod-ch/hooks'\n\nfunction DemoField(props: { value: string; onChange: (value: string) => void }) {\n  const [value, setValue] = useControllableValue(props)\n\n  return <input value={value} onInput={(event) => setValue(event.currentTarget.value)} />\n}\n\nexport default function UseControllableValueDemo() {\n  const [value, setValue] = useState('controlled')\n\n  return (\n    <div>\n      <DemoField value={value} onChange={setValue} />\n      <p><strong>Parent value:</strong> {value}</p>\n    </div>\n  )\n}\n`,
usePrevious: `import { useState } from 'preact/hooks'\nimport { usePrevious } from '@kamod-ch/hooks'\n\nexport default function UsePreviousDemo() {\n  const [value, setValue] = useState('first')\n  const previous = usePrevious(value)\n\n  return (\n    <div>\n      <input value={value} onInput={(event) => setValue(event.currentTarget.value)} />\n      <p><strong>Current:</strong> {value}</p>\n      <p><strong>Previous:</strong> {previous ?? 'none'}</p>\n    </div>\n  )\n}\n`,
useLatest: `import { useState } from 'preact/hooks'\nimport { useLatest } from '@kamod-ch/hooks'\n\nexport default function UseLatestDemo() {\n  const [value, setValue] = useState('initial')\n  const latest = useLatest(value)\n\n  return (\n    <div>\n      <input value={value} onInput={(event) => setValue(event.currentTarget.value)} />\n      <p><strong>latest.current:</strong> {latest.current}</p>\n    </div>\n  )\n}\n`,
useMemoizedFn: `import { useState } from 'preact/hooks'\nimport { useMemoizedFn } from '@kamod-ch/hooks'\n\nexport default function UseMemoizedFnDemo() {\n  const [count, setCount] = useState(0)\n  const increment = useMemoizedFn(() => setCount((value) => value + 1))\n\n  return (\n    <div>\n      <p><strong>Count:</strong> {count}</p>\n      <button type=\"button\" onClick={increment}>Increment with stable callback</button>\n    </div>\n  )\n}\n`,
useCreation: `import { useState } from 'preact/hooks'\nimport { useCreation } from '@kamod-ch/hooks'\n\nexport default function UseCreationDemo() {\n  const [seed, setSeed] = useState(1)\n  const value = useCreation(() => ({ seed, createdAt: Date.now() }), [seed])\n\n  return (\n    <div>\n      <pre>{JSON.stringify(value, null, 2)}</pre>\n      <button type=\"button\" onClick={() => setSeed((current) => current + 1)}>Recreate with new dep</button>\n    </div>\n  )\n}\n`,
useUpdate: `import { useState } from 'preact/hooks'\nimport { useUpdate } from '@kamod-ch/hooks'\n\nexport default function UseUpdateDemo() {\n  const [renders, setRenders] = useState(1)\n  const forceUpdate = useUpdate()\n\n  return (\n    <div>\n      <p><strong>Tracked value:</strong> {renders}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setRenders((value) => value + 1)}>Change state</button>\n        <button type=\"button\" onClick={forceUpdate}>Force render</button>\n      </div>\n    </div>\n  )\n}\n`,
useSafeState: `import { useState } from 'preact/hooks'\nimport { useSafeState } from '@kamod-ch/hooks'\n\nfunction Child() {\n  const [value, setValue] = useSafeState('waiting')\n\n  return (\n    <div>\n      <p><strong>Status:</strong> {value}</p>\n      <button type=\"button\" onClick={() => {\n        setValue('loading')\n        window.setTimeout(() => setValue('resolved safely'), 800)\n      }}>Start async update</button>\n    </div>\n  )\n}\n\nexport default function UseSafeStateDemo() {\n  const [visible, setVisible] = useState(true)\n  return (\n    <div>\n      <button type=\"button\" onClick={() => setVisible((value) => !value)}>{visible ? 'Unmount child' : 'Mount child'}</button>\n      {visible ? <Child /> : <p>Child removed before late updates can land.</p>}\n    </div>\n  )\n}\n`,
useMount: `import { useState } from 'preact/hooks'\nimport { useMount } from '@kamod-ch/hooks'\n\nfunction Child({ onMount }: { onMount: () => void }) {\n  useMount(onMount)\n  return <p>Mounted child content.</p>\n}\n\nexport default function UseMountDemo() {\n  const [visible, setVisible] = useState(true)\n  const [mounts, setMounts] = useState(1)\n\n  return (\n    <div>\n      <p><strong>Mount count:</strong> {mounts}</p>\n      <button type=\"button\" onClick={() => setVisible((value) => !value)}>{visible ? 'Unmount' : 'Mount'}</button>\n      {visible ? <Child onMount={() => setMounts((value) => value + 1)} /> : null}\n    </div>\n  )\n}\n`,
useUnmount: `import { useState } from 'preact/hooks'\nimport { useUnmount } from '@kamod-ch/hooks'\n\nfunction Child({ onUnmount }: { onUnmount: () => void }) {\n  useUnmount(onUnmount)\n  return <p>Hide this child to trigger cleanup.</p>\n}\n\nexport default function UseUnmountDemo() {\n  const [visible, setVisible] = useState(true)\n  const [unmounts, setUnmounts] = useState(0)\n\n  return (\n    <div>\n      <p><strong>Unmount count:</strong> {unmounts}</p>\n      <button type=\"button\" onClick={() => setVisible((value) => !value)}>{visible ? 'Unmount child' : 'Mount child'}</button>\n      {visible ? <Child onUnmount={() => setUnmounts((value) => value + 1)} /> : null}\n    </div>\n  )\n}\n`,
useUnmountedRef: `import { useState } from 'preact/hooks'\nimport { useUnmountedRef } from '@kamod-ch/hooks'\n\nfunction Child() {\n  const ref = useUnmountedRef()\n  return <p><strong>Unmounted flag:</strong> {String(ref.current)}</p>\n}\n\nexport default function UseUnmountedRefDemo() {\n  const [visible, setVisible] = useState(true)\n  return (\n    <div>\n      <button type=\"button\" onClick={() => setVisible((value) => !value)}>{visible ? 'Unmount child' : 'Mount child'}</button>\n      {visible ? <Child /> : <p>After unmount the ref inside the child becomes true.</p>}\n    </div>\n  )\n}\n`,
useUpdateEffect: `import { useState } from 'preact/hooks'\nimport { useUpdateEffect } from '@kamod-ch/hooks'\n\nexport default function UseUpdateEffectDemo() {\n  const [value, setValue] = useState(0)\n  const [runs, setRuns] = useState(0)\n\n  useUpdateEffect(() => {\n    setRuns((count) => count + 1)\n  }, [value])\n\n  return (\n    <div>\n      <p><strong>Value:</strong> {value}</p>\n      <p><strong>Effect runs after mount:</strong> {runs}</p>\n      <button type=\"button\" onClick={() => setValue((count) => count + 1)}>Increment</button>\n    </div>\n  )\n}\n`,
useUpdateLayoutEffect: `import { useState } from 'preact/hooks'\nimport { useUpdateLayoutEffect } from '@kamod-ch/hooks'\n\nexport default function UseUpdateLayoutEffectDemo() {\n  const [value, setValue] = useState(0)\n  const [runs, setRuns] = useState(0)\n\n  useUpdateLayoutEffect(() => {\n    setRuns((count) => count + 1)\n  }, [value])\n\n  return (\n    <div>\n      <p><strong>Value:</strong> {value}</p>\n      <p><strong>Layout effect runs after mount:</strong> {runs}</p>\n      <button type=\"button\" onClick={() => setValue((count) => count + 1)}>Increment</button>\n    </div>\n  )\n}\n`,
useDeepCompareEffect: `import { useState } from 'preact/hooks'\nimport { useDeepCompareEffect } from '@kamod-ch/hooks'\n\nexport default function UseDeepCompareEffectDemo() {\n  const [count, setCount] = useState(0)\n  const [runs, setRuns] = useState(0)\n  const config = { page: 1, filters: ['open'] }\n\n  useDeepCompareEffect(() => {\n    setRuns((value) => value + 1)\n  }, [config])\n\n  return (\n    <div>\n      <p><strong>Unrelated count:</strong> {count}</p>\n      <p><strong>Effect runs:</strong> {runs}</p>\n      <button type=\"button\" onClick={() => setCount((value) => value + 1)}>Re-render with deep-equal deps</button>\n    </div>\n  )\n}\n`,
useDeepCompareLayoutEffect: `import { useState } from 'preact/hooks'\nimport { useDeepCompareLayoutEffect } from '@kamod-ch/hooks'\n\nexport default function UseDeepCompareLayoutEffectDemo() {\n  const [count, setCount] = useState(0)\n  const [runs, setRuns] = useState(0)\n  const config = { dense: true, columns: ['name', 'status'] }\n\n  useDeepCompareLayoutEffect(() => {\n    setRuns((value) => value + 1)\n  }, [config])\n\n  return (\n    <div>\n      <p><strong>Unrelated count:</strong> {count}</p>\n      <p><strong>Layout effect runs:</strong> {runs}</p>\n      <button type=\"button\" onClick={() => setCount((value) => value + 1)}>Re-render with deep-equal deps</button>\n    </div>\n  )\n}\n`,
useTrackedEffect: `import { useState } from 'preact/hooks'\nimport { useTrackedEffect } from '@kamod-ch/hooks'\n\nexport default function UseTrackedEffectDemo() {\n  const [left, setLeft] = useState(0)\n  const [right, setRight] = useState(0)\n  const [changed, setChanged] = useState<number[]>([])\n\n  useTrackedEffect((changes) => {\n    setChanged(changes ?? [])\n  }, [left, right])\n\n  return (\n    <div>\n      <p><strong>Left:</strong> {left} · <strong>Right:</strong> {right}</p>\n      <p><strong>Changed dependency indexes:</strong> {changed.join(', ') || 'none yet'}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setLeft((value) => value + 1)}>Change left</button>\n        <button type=\"button\" onClick={() => setRight((value) => value + 1)}>Change right</button>\n      </div>\n    </div>\n  )\n}\n`,
useAsyncEffect: `import { useState } from 'preact/hooks'\nimport { useAsyncEffect } from '@kamod-ch/hooks'\n\nexport default function UseAsyncEffectDemo() {\n  const [query, setQuery] = useState('kamod')\n  const [status, setStatus] = useState('idle')\n\n  useAsyncEffect(async () => {\n    setStatus('loading')\n    await new Promise((resolve) => window.setTimeout(resolve, 500))\n    setStatus('loaded for ' + query)\n  }, [query])\n\n  return (\n    <div>\n      <input value={query} onInput={(event) => setQuery(event.currentTarget.value)} />\n      <p><strong>Status:</strong> {status}</p>\n    </div>\n  )\n}\n`,
useDebounce: `import { useState } from 'preact/hooks'\nimport { useDebounce } from '@kamod-ch/hooks'\n\nexport default function UseDebounceDemo() {\n  const [value, setValue] = useState('')\n  const debounced = useDebounce(value, { wait: 400 })\n\n  return (\n    <div>\n      <input value={value} onInput={(event) => setValue(event.currentTarget.value)} placeholder=\"Type quickly\" />\n      <p><strong>Immediate:</strong> {value || '—'}</p>\n      <p><strong>Debounced:</strong> {debounced || '—'}</p>\n    </div>\n  )\n}\n`,
useDebounceFn: `import { useState } from 'preact/hooks'\nimport { useDebounceFn } from '@kamod-ch/hooks'\n\nexport default function UseDebounceFnDemo() {\n  const [count, setCount] = useState(0)\n  const { run, cancel, flush } = useDebounceFn(() => setCount((value) => value + 1), { wait: 500 })\n\n  return (\n    <div>\n      <p><strong>Debounced count:</strong> {count}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => { run(); run(); run() }}>Queue burst</button>\n        <button type=\"button\" onClick={flush}>Flush</button>\n        <button type=\"button\" onClick={cancel}>Cancel</button>\n      </div>\n    </div>\n  )\n}\n`,
useDebounceEffect: `import { useState } from 'preact/hooks'\nimport { useDebounceEffect } from '@kamod-ch/hooks'\n\nexport default function UseDebounceEffectDemo() {\n  const [query, setQuery] = useState('')\n  const [runs, setRuns] = useState(0)\n\n  useDebounceEffect(() => {\n    if (query) setRuns((value) => value + 1)\n  }, [query], { wait: 400 })\n\n  return (\n    <div>\n      <input value={query} onInput={(event) => setQuery(event.currentTarget.value)} placeholder=\"Type quickly\" />\n      <p><strong>Debounced effect runs:</strong> {runs}</p>\n    </div>\n  )\n}\n`,
useThrottle: `import { useState } from 'preact/hooks'\nimport { useThrottle } from '@kamod-ch/hooks'\n\nexport default function UseThrottleDemo() {\n  const [value, setValue] = useState(0)\n  const throttled = useThrottle(value, { wait: 500 })\n\n  return (\n    <div>\n      <input type=\"range\" min={0} max={100} value={value} onInput={(event) => setValue(Number(event.currentTarget.value))} />\n      <p><strong>Immediate:</strong> {value}</p>\n      <p><strong>Throttled:</strong> {throttled}</p>\n    </div>\n  )\n}\n`,
useThrottleFn: `import { useState } from 'preact/hooks'\nimport { useThrottleFn } from '@kamod-ch/hooks'\n\nexport default function UseThrottleFnDemo() {\n  const [count, setCount] = useState(0)\n  const { run, cancel, flush } = useThrottleFn(() => setCount((value) => value + 1), { wait: 500 })\n\n  return (\n    <div>\n      <p><strong>Throttled count:</strong> {count}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => { run(); run(); run() }}>Trigger burst</button>\n        <button type=\"button\" onClick={flush}>Flush</button>\n        <button type=\"button\" onClick={cancel}>Cancel</button>\n      </div>\n    </div>\n  )\n}\n`,
useThrottleEffect: `import { useState } from 'preact/hooks'\nimport { useThrottleEffect } from '@kamod-ch/hooks'\n\nexport default function UseThrottleEffectDemo() {\n  const [query, setQuery] = useState('')\n  const [runs, setRuns] = useState(0)\n\n  useThrottleEffect(() => {\n    if (query) setRuns((value) => value + 1)\n  }, [query], { wait: 500 })\n\n  return (\n    <div>\n      <input value={query} onInput={(event) => setQuery(event.currentTarget.value)} placeholder=\"Type quickly\" />\n      <p><strong>Throttled effect runs:</strong> {runs}</p>\n    </div>\n  )\n}\n`,
useInterval: `import { useState } from 'preact/hooks'\nimport { useInterval } from '@kamod-ch/hooks'\n\nexport default function UseIntervalDemo() {\n  const [running, setRunning] = useState(false)\n  const [ticks, setTicks] = useState(0)\n  useInterval(() => setTicks((value) => value + 1), running ? 1000 : undefined)\n\n  return (\n    <div>\n      <p><strong>Ticks:</strong> {ticks}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setRunning((value) => !value)}>{running ? 'Stop' : 'Start'}</button>\n        <button type=\"button\" onClick={() => setTicks(0)}>Reset</button>\n      </div>\n    </div>\n  )\n}\n`,
useTimeout: `import { useState } from 'preact/hooks'\nimport { useTimeout } from '@kamod-ch/hooks'\n\nexport default function UseTimeoutDemo() {\n  const [armed, setArmed] = useState(false)\n  const [status, setStatus] = useState('idle')\n  useTimeout(() => { if (armed) setStatus('completed') }, armed ? 1000 : undefined)\n\n  return (\n    <div>\n      <p><strong>Status:</strong> {status}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => { setStatus('waiting'); setArmed(true) }}>Start timeout</button>\n        <button type=\"button\" onClick={() => { setArmed(false); setStatus('cancelled') }}>Cancel</button>\n      </div>\n    </div>\n  )\n}\n`,
useRafInterval: `import { useState } from 'preact/hooks'\nimport { useRafInterval } from '@kamod-ch/hooks'\n\nexport default function UseRafIntervalDemo() {\n  const [running, setRunning] = useState(false)\n  const [ticks, setTicks] = useState(0)\n  useRafInterval(() => setTicks((value) => value + 1), running ? 300 : undefined)\n\n  return (\n    <div>\n      <p><strong>Frame ticks:</strong> {ticks}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setRunning((value) => !value)}>{running ? 'Stop' : 'Start'}</button>\n        <button type=\"button\" onClick={() => setTicks(0)}>Reset</button>\n      </div>\n    </div>\n  )\n}\n`,
useRafTimeout: `import { useState } from 'preact/hooks'\nimport { useRafTimeout } from '@kamod-ch/hooks'\n\nexport default function UseRafTimeoutDemo() {\n  const [armed, setArmed] = useState(false)\n  const [status, setStatus] = useState('idle')\n  useRafTimeout(() => { if (armed) setStatus('completed') }, armed ? 600 : undefined)\n\n  return (\n    <div>\n      <p><strong>Status:</strong> {status}</p>\n      <button type=\"button\" onClick={() => { setStatus('waiting'); setArmed(true) }}>Start RAF timeout</button>\n    </div>\n  )\n}\n`,
useCountDown: `import { useState } from 'preact/hooks'\nimport { useCountDown } from '@kamod-ch/hooks'\n\nexport default function UseCountDownDemo() {\n  const [target, setTarget] = useState(() => Date.now() + 5000)\n  const [left, formatted] = useCountDown({ targetDate: target })\n\n  return (\n    <div>\n      <p><strong>Milliseconds left:</strong> {left}</p>\n      <p><strong>Seconds:</strong> {formatted.seconds}</p>\n      <button type=\"button\" onClick={() => setTarget(Date.now() + 5000)}>Restart 5 second countdown</button>\n    </div>\n  )\n}\n`,
useRafState: `import { useRafState } from '@kamod-ch/hooks'\n\nexport default function UseRafStateDemo() {\n  const [value, setValue] = useRafState(0)\n\n  return (\n    <div>\n      <p><strong>Value:</strong> {value}</p>\n      <button type=\"button\" onClick={() => { setValue((count) => count + 1); setValue((count) => count + 1) }}>Queue two RAF updates</button>\n    </div>\n  )\n}\n`,
useClickAway: `import { useRef, useState } from 'preact/hooks'\nimport { useClickAway } from '@kamod-ch/hooks'\n\nexport default function UseClickAwayDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const [outsideClicks, setOutsideClicks] = useState(0)\n  useClickAway(() => setOutsideClicks((value) => value + 1), ref)\n\n  return (\n    <div class=\"demo-click-away-wrap\">\n      <div ref={ref} class=\"demo-target-box\">Click inside this box.</div>\n      <button type=\"button\">Click outside target</button>\n      <p><strong>Outside clicks:</strong> {outsideClicks}</p>\n    </div>\n  )\n}\n`,
useEventListener: `import { useRef, useState } from 'preact/hooks'\nimport { useEventListener } from '@kamod-ch/hooks'\n\nexport default function UseEventListenerDemo() {\n  const ref = useRef<HTMLButtonElement>(null)\n  const [clicks, setClicks] = useState(0)\n  useEventListener('click', () => setClicks((value) => value + 1), { target: ref })\n\n  return (\n    <div>\n      <button ref={ref} type=\"button\">Native listener target</button>\n      <p><strong>Captured clicks:</strong> {clicks}</p>\n    </div>\n  )\n}\n`,
useHover: `import { useRef } from 'preact/hooks'\nimport { useHover } from '@kamod-ch/hooks'\n\nexport default function UseHoverDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const hovering = useHover(ref)\n\n  return (\n    <div>\n      <div ref={ref} class=\"demo-target-box\">Hover this area</div>\n      <p><strong>Hovering:</strong> {String(hovering)}</p>\n    </div>\n  )\n}\n`,
useFocusWithin: `import { useRef } from 'preact/hooks'\nimport { useFocusWithin } from '@kamod-ch/hooks'\n\nexport default function UseFocusWithinDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const focused = useFocusWithin(ref)\n\n  return (\n    <div>\n      <div ref={ref} class=\"demo-target-box\">\n        <input placeholder=\"Focus me\" />\n        <button type=\"button\">Focusable button</button>\n      </div>\n      <p><strong>Focus within:</strong> {String(focused)}</p>\n    </div>\n  )\n}\n`,
useKeyPress: `import { useRef, useState } from 'preact/hooks'\nimport { useKeyPress } from '@kamod-ch/hooks'\n\nexport default function UseKeyPressDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const [count, setCount] = useState(0)\n  const [last, setLast] = useState('none')\n\n  useKeyPress('k', (event, key) => {\n    setCount((value) => value + 1)\n    setLast(String(key || event.key))\n  }, { target: ref })\n\n  return (\n    <div>\n      <div ref={ref} class=\"demo-target-box\" tabIndex={0}>Focus here and press the “k” key.</div>\n      <p><strong>Last key:</strong> {last}</p>\n      <p><strong>Recognized presses:</strong> {count}</p>\n    </div>\n  )\n}\n`,
useMouse: `import { useRef } from 'preact/hooks'\nimport { useMouse } from '@kamod-ch/hooks'\n\nexport default function UseMouseDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const mouse = useMouse(ref)\n\n  return (\n    <div>\n      <div ref={ref} class=\"demo-target-box demo-large-box\">Move the pointer here.</div>\n      <p><strong>Element coordinates:</strong> {Math.round(mouse.elementX)}, {Math.round(mouse.elementY)}</p>\n    </div>\n  )\n}\n`,
useScroll: `import { useRef } from 'preact/hooks'\nimport { useScroll } from '@kamod-ch/hooks'\n\nexport default function UseScrollDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const position = useScroll(ref)\n\n  return (\n    <div>\n      <div ref={ref} class=\"demo-scroll-box\">{Array.from({ length: 20 }, (_, index) => <p key={index}>Scrollable row {index + 1}</p>)}</div>\n      <p><strong>Top:</strong> {position?.top ?? 0}</p>\n    </div>\n  )\n}\n`,
useTextSelection: `import { useRef } from 'preact/hooks'\nimport { useTextSelection } from '@kamod-ch/hooks'\n\nexport default function UseTextSelectionDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const selection = useTextSelection(ref)\n\n  return (\n    <div>\n      <div ref={ref} class=\"demo-target-box\">Select some text inside this paragraph to inspect the current selection.</div>\n      <p><strong>Selected text:</strong> {selection.text || 'none'}</p>\n    </div>\n  )\n}\n`,
useMutationObserver: `import { useRef, useState } from 'preact/hooks'\nimport { useMutationObserver } from '@kamod-ch/hooks'\n\nexport default function UseMutationObserverDemo() {\n  const ref = useRef<HTMLUListElement>(null)\n  const [items, setItems] = useState(['first'])\n  const [mutations, setMutations] = useState(0)\n\n  useMutationObserver(() => setMutations((value) => value + 1), ref, { childList: true })\n\n  return (\n    <div>\n      <ul ref={ref}>{items.map((item) => <li key={item}>{item}</li>)}</ul>\n      <p><strong>Mutation callbacks:</strong> {mutations}</p>\n      <button type=\"button\" onClick={() => setItems((value) => [...value, 'item-' + (value.length + 1)])}>Append item</button>\n    </div>\n  )\n}\n`,
useSize: `import { useRef, useState } from 'preact/hooks'\nimport { useSize } from '@kamod-ch/hooks'\n\nexport default function UseSizeDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const [width, setWidth] = useState(220)\n  const size = useSize(ref)\n\n  return (\n    <div>\n      <input type=\"range\" min={160} max={360} value={width} onInput={(event) => setWidth(Number(event.currentTarget.value))} />\n      <div ref={ref} class=\"demo-target-box\" style={{ width: width + 'px' }}>Observed box</div>\n      <p><strong>Measured size:</strong> {size?.width ?? 0} × {size?.height ?? 0}</p>\n    </div>\n  )\n}\n`,
useDocumentVisibility: `import { useDocumentVisibility } from '@kamod-ch/hooks'\n\nexport default function UseDocumentVisibilityDemo() {\n  const visibility = useDocumentVisibility()\n  return <p><strong>document.visibilityState:</strong> {visibility ?? 'unsupported'}</p>\n}\n`,
useNetwork: `import { useNetwork } from '@kamod-ch/hooks'\n\nexport default function UseNetworkDemo() {\n  const network = useNetwork()\n  return <pre>{JSON.stringify(network, null, 2)}</pre>\n}\n`,
useInViewport: `import { useRef } from 'preact/hooks'\nimport { useInViewport } from '@kamod-ch/hooks'\n\nexport default function UseInViewportDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const [inViewport, ratio] = useInViewport(ref, { threshold: [0, 0.5, 1] })\n\n  return (\n    <div>\n      <div class=\"demo-scroll-box\">\n        <div style={{ height: '180px' }} />\n        <div ref={ref} class=\"demo-target-box\">Observed target</div>\n        <div style={{ height: '180px' }} />\n      </div>\n      <p><strong>Visible:</strong> {String(inViewport)} · <strong>Ratio:</strong> {ratio}</p>\n    </div>\n  )\n}\n`,
useInfiniteScroll: `import { useRef } from 'preact/hooks'\nimport { useInfiniteScroll } from '@kamod-ch/hooks'\n\nconst total = 18\nasync function load(current?: { list: string[]; cursor: number }) {\n  await new Promise((resolve) => window.setTimeout(resolve, 300))\n  const cursor = current?.cursor ?? 0\n  const next = Array.from({ length: 6 }, (_, index) => 'Item ' + (cursor + index + 1))\n  return { list: next, cursor: cursor + next.length }\n}\n\nexport default function UseInfiniteScrollDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const result = useInfiniteScroll(load, {\n    target: ref,\n    isNoMore: (data) => (data?.cursor ?? 0) >= total\n  })\n\n  return (\n    <div>\n      <div ref={ref} class=\"demo-scroll-box\">\n        {(result.data?.list ?? []).map((item) => <p key={item}>{item}</p>)}\n        <p>{result.loadingMore ? 'Loading more…' : result.noMore ? 'No more items.' : 'Scroll to the bottom.'}</p>\n      </div>\n      <button type=\"button\" onClick={result.reload}>Reload</button>\n    </div>\n  )\n}\n`,
useVirtualList: `import { useMemo, useRef } from 'preact/hooks'\nimport { useVirtualList } from '@kamod-ch/hooks'\n\nexport default function UseVirtualListDemo() {\n  const list = useMemo(() => Array.from({ length: 200 }, (_, index) => 'Row ' + (index + 1)), [])\n  const containerRef = useRef<HTMLDivElement>(null)\n  const wrapperRef = useRef<HTMLDivElement>(null)\n  const [visible, scrollTo] = useVirtualList(list, { containerTarget: containerRef, wrapperTarget: wrapperRef, itemHeight: 36, overscan: 4 })\n\n  return (\n    <div>\n      <p><strong>Total items:</strong> {list.length} · <strong>Rendered items:</strong> {visible.length}</p>\n      <button type=\"button\" onClick={() => scrollTo(120)}>Scroll to item 121</button>\n      <div ref={containerRef} class=\"demo-scroll-box\" style={{ height: '220px' }}>\n        <div ref={wrapperRef}>\n          {visible.map((item) => <div key={item.index} class=\"demo-virtual-row\">{item.data}</div>)}\n        </div>\n      </div>\n    </div>\n  )\n}\n`,
useFullscreen: `import { useRef } from 'preact/hooks'\nimport { useFullscreen } from '@kamod-ch/hooks'\n\nexport default function UseFullscreenDemo() {\n  const ref = useRef<HTMLDivElement>(null)\n  const [isFullscreen, actions] = useFullscreen(ref)\n\n  return (\n    <div>\n      <div ref={ref} class=\"demo-target-box demo-large-box\">Fullscreen target</div>\n      <p><strong>Fullscreen:</strong> {String(isFullscreen)} · <strong>Supported:</strong> {String(actions.isEnabled)}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={actions.enterFullscreen}>Enter</button>\n        <button type=\"button\" onClick={actions.exitFullscreen}>Exit</button>\n      </div>\n    </div>\n  )\n}\n`,
useLocalStorageState: `import { useLocalStorageState } from '@kamod-ch/hooks'\n\nconst key = 'kamod-hooks-demo-use-local-storage-state'\n\nexport default function UseLocalStorageStateDemo() {\n  const [value, setValue] = useLocalStorageState<string>(key, { defaultValue: 'hello' })\n\n  return (\n    <div>\n      <input value={value} onInput={(event) => setValue(event.currentTarget.value)} />\n      <p><strong>Stored value:</strong> {value}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setValue('reset')}>Set reset</button>\n        <button type=\"button\" onClick={() => setValue(undefined)}>Clear</button>\n      </div>\n    </div>\n  )\n}\n`,
useSessionStorageState: `import { useSessionStorageState } from '@kamod-ch/hooks'\n\nconst key = 'kamod-hooks-demo-use-session-storage-state'\n\nexport default function UseSessionStorageStateDemo() {\n  const [value, setValue] = useSessionStorageState<string>(key, { defaultValue: 'session' })\n\n  return (\n    <div>\n      <input value={value} onInput={(event) => setValue(event.currentTarget.value)} />\n      <p><strong>Stored value:</strong> {value}</p>\n      <button type=\"button\" onClick={() => setValue(undefined)}>Clear</button>\n    </div>\n  )\n}\n`,
useCookieState: `import { useCookieState } from '@kamod-ch/hooks'\n\nconst key = 'kamod-hooks-demo-use-cookie-state'\n\nexport default function UseCookieStateDemo() {\n  const [value, setValue] = useCookieState(key, { defaultValue: 'cookie', path: '/' })\n\n  return (\n    <div>\n      <input value={value ?? ''} onInput={(event) => setValue(event.currentTarget.value, { path: '/' })} />\n      <p><strong>Cookie value:</strong> {value ?? 'undefined'}</p>\n      <button type=\"button\" onClick={() => setValue(undefined, { path: '/', expires: -1 })}>Delete cookie</button>\n    </div>\n  )\n}\n`,
useUrlState: `import { useEffect, useRef } from 'preact/hooks'\nimport { useUrlState } from '@kamod-ch/hooks'\n\nexport default function UseUrlStateDemo() {\n  const original = useRef('')\n  useEffect(() => {\n    original.current = window.location.search\n  }, [])\n\n  const [state, setState] = useUrlState({ khDemoView: 'cards', khDemoFilter: 'all' }, { navigateMode: 'replace' })\n\n  return (\n    <div>\n      <p><strong>Query state:</strong> {JSON.stringify(state)}</p>\n      <p><strong>Current search:</strong> {window.location.search || '(empty)'}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setState((current) => ({ ...current, khDemoView: current.khDemoView === 'cards' ? 'table' : 'cards' }))}>Toggle view</button>\n        <button type=\"button\" onClick={() => setState({ khDemoView: 'cards', khDemoFilter: 'all' })}>Reset params</button>\n        <button type=\"button\" onClick={() => window.history.replaceState(window.history.state, '', window.location.pathname + original.current + window.location.hash)}>Restore original URL</button>\n      </div>\n    </div>\n  )\n}\n`,
useTheme: `import { useTheme } from '@kamod-ch/hooks'\n\nexport default function UseThemeDemo() {\n  const { theme, themeMode, setThemeMode } = useTheme({ localStorageKey: 'kamod-hooks-demo-theme' })\n\n  return (\n    <div>\n      <p><strong>Resolved theme:</strong> {theme}</p>\n      <p><strong>Mode:</strong> {themeMode}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setThemeMode('light')}>Light</button>\n        <button type=\"button\" onClick={() => setThemeMode('dark')}>Dark</button>\n        <button type=\"button\" onClick={() => setThemeMode('system')}>System</button>\n      </div>\n    </div>\n  )\n}\n`,
useResponsive: `import { useEffect, useState } from 'preact/hooks'\nimport { configResponsive, useResponsive } from '@kamod-ch/hooks'\n\nexport default function UseResponsiveDemo() {\n  const [width, setWidth] = useState(0)\n  const info = useResponsive()\n\n  useEffect(() => {\n    configResponsive({ mobile: 0, tablet: 640, desktop: 1024 })\n    const update = () => setWidth(window.innerWidth)\n    update()\n    window.addEventListener('resize', update)\n    return () => window.removeEventListener('resize', update)\n  }, [])\n\n  return (\n    <div>\n      <p><strong>Window width:</strong> {width}</p>\n      <pre>{JSON.stringify(info, null, 2)}</pre>\n      <p>Resize the browser window to see the flags update.</p>\n    </div>\n  )\n}\n`,
useTitle: `import { useState } from 'preact/hooks'\nimport { useTitle } from '@kamod-ch/hooks'\n\nexport default function UseTitleDemo() {\n  const [title, setTitle] = useState('Kamod Hooks demo title')\n  useTitle(title, { restoreOnUnmount: false })\n\n  return (\n    <div>\n      <input value={title} onInput={(event) => setTitle(event.currentTarget.value)} />\n      <p><strong>document.title:</strong> {title}</p>\n    </div>\n  )\n}\n`,
useFavicon: `import { useState } from 'preact/hooks'\nimport { useFavicon } from '@kamod-ch/hooks'\n\nconst green = 'data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 32 32%22%3E%3Crect width=%2232%22 height=%2232%22 rx=%229%22 fill=%22%2310b981%22/%3E%3C/svg%3E'\nconst blue = 'data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 32 32%22%3E%3Crect width=%2232%22 height=%2232%22 rx=%229%22 fill=%22%233b82f6%22/%3E%3C/svg%3E'\n\nexport default function UseFaviconDemo() {\n  const [href, setHref] = useState(green)\n  useFavicon(href)\n\n  return (\n    <div>\n      <p><strong>Active favicon:</strong> {href === green ? 'green square' : 'blue square'}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setHref(green)}>Green</button>\n        <button type=\"button\" onClick={() => setHref(blue)}>Blue</button>\n      </div>\n    </div>\n  )\n}\n`,
useExternal: `import { useMemo, useState } from 'preact/hooks'\nimport { useExternal } from '@kamod-ch/hooks'\n\nexport default function UseExternalDemo() {\n  const [enabled, setEnabled] = useState(false)\n  const scriptUrl = useMemo(() => {\n    const blob = new Blob([\"window.__kamodHooksExternalLoaded = 'ready'\"], { type: 'text/javascript' })\n    return URL.createObjectURL(blob)\n  }, [])\n  const status = useExternal(enabled ? scriptUrl : undefined)\n\n  return (\n    <div>\n      <p><strong>Status:</strong> {status}</p>\n      <button type=\"button\" onClick={() => setEnabled(true)}>Load script</button>\n    </div>\n  )\n}\n`,
useDrag: `import { useRef, useState } from 'preact/hooks'\nimport { useDrag, useDrop } from '@kamod-ch/hooks'\n\nexport default function UseDragDemo() {\n  const sourceRef = useRef<HTMLDivElement>(null)\n  const targetRef = useRef<HTMLDivElement>(null)\n  const [dropped, setDropped] = useState('nothing yet')\n  useDrag({ label: 'Dragged card' }, sourceRef)\n  useDrop(targetRef, { onDom: (content) => setDropped(content?.label ?? 'received data') })\n\n  return (\n    <div class=\"demo-grid\">\n      <div ref={sourceRef} class=\"demo-target-box\">Drag me</div>\n      <div ref={targetRef} class=\"demo-target-box\">Drop here</div>\n      <p><strong>Last drop:</strong> {dropped}</p>\n    </div>\n  )\n}\n`,
useDrop: `import { useRef, useState } from 'preact/hooks'\nimport { useDrag, useDrop } from '@kamod-ch/hooks'\n\nexport default function UseDropDemo() {\n  const sourceRef = useRef<HTMLDivElement>(null)\n  const targetRef = useRef<HTMLDivElement>(null)\n  const [dropped, setDropped] = useState('nothing yet')\n  useDrag({ label: 'Dragged payload' }, sourceRef)\n  useDrop(targetRef, { onDom: (content) => setDropped(content?.label ?? 'received data') })\n\n  return (\n    <div class=\"demo-grid\">\n      <div ref={sourceRef} class=\"demo-target-box\">Drag this payload</div>\n      <div ref={targetRef} class=\"demo-target-box\">Drop target</div>\n      <p><strong>Drop result:</strong> {dropped}</p>\n    </div>\n  )\n}\n`,
useLongPress: `import { useRef, useState } from 'preact/hooks'\nimport { useLongPress } from '@kamod-ch/hooks'\n\nexport default function UseLongPressDemo() {\n  const ref = useRef<HTMLButtonElement>(null)\n  const [count, setCount] = useState(0)\n  useLongPress(() => setCount((value) => value + 1), ref, { delay: 600 })\n\n  return (\n    <div>\n      <button ref={ref} type=\"button\">Press and hold me</button>\n      <p><strong>Long presses:</strong> {count}</p>\n    </div>\n  )\n}\n`,
useRequest: `import { useState } from 'preact/hooks'\nimport { useRequest } from '@kamod-ch/hooks'\n\nasync function loadUser(shouldFail: boolean) {\n  await new Promise((resolve) => window.setTimeout(resolve, 700))\n  if (shouldFail) throw new Error('Demo request failed')\n  return { id: 1, name: 'Kamod User' }\n}\n\nexport default function UseRequestDemo() {\n  const [shouldFail, setShouldFail] = useState(false)\n  const request = useRequest(() => loadUser(shouldFail), { manual: true, retryCount: 1 })\n\n  return (\n    <div>\n      <label class=\"demo-option\">\n        <input type=\"checkbox\" checked={shouldFail} onInput={(event) => setShouldFail(event.currentTarget.checked)} />\n        Fail next request\n      </label>\n      <pre>{JSON.stringify({ loading: request.loading, data: request.data, error: request.error?.message ?? null }, null, 2)}</pre>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => request.run()}>Run</button>\n        <button type=\"button\" onClick={() => request.refresh()}>Refresh</button>\n        <button type=\"button\" onClick={() => request.cancel()}>Cancel</button>\n      </div>\n    </div>\n  )\n}\n`,
useLockFn: `import { useState } from 'preact/hooks'\nimport { useLockFn } from '@kamod-ch/hooks'\n\nexport default function UseLockFnDemo() {\n  const [runs, setRuns] = useState(0)\n  const [inFlight, setInFlight] = useState(false)\n  const locked = useLockFn(async () => {\n    setInFlight(true)\n    await new Promise((resolve) => window.setTimeout(resolve, 500))\n    setRuns((value) => value + 1)\n    setInFlight(false)\n  })\n\n  return (\n    <div>\n      <p><strong>Completed runs:</strong> {runs}</p>\n      <p><strong>In flight:</strong> {String(inFlight)}</p>\n      <button type=\"button\" onClick={() => { locked(); locked(); locked() }}>Trigger three concurrent calls</button>\n    </div>\n  )\n}\n`,
usePagination: `import { usePagination } from '@kamod-ch/hooks'\n\nasync function service({ current, pageSize }: { current: number; pageSize: number }) {\n  await new Promise((resolve) => window.setTimeout(resolve, 200))\n  const total = 42\n  const start = (current - 1) * pageSize\n  return { total, list: Array.from({ length: pageSize }, (_, index) => 'Item ' + (start + index + 1)) }\n}\n\nexport default function UsePaginationDemo() {\n  const result = usePagination(service)\n\n  return (\n    <div>\n      <p><strong>Page:</strong> {result.pagination.current} / {result.pagination.totalPage}</p>\n      <ul>{(result.data?.list ?? []).map((item) => <li key={item}>{item}</li>)}</ul>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => result.pagination.changeCurrent(Math.max(1, result.pagination.current - 1))}>Previous</button>\n        <button type=\"button\" onClick={() => result.pagination.changeCurrent(result.pagination.current + 1)}>Next</button>\n      </div>\n    </div>\n  )\n}\n`,
useAntdTable: `import { useAntdTable } from '@kamod-ch/hooks'\n\nasync function service({ current, pageSize }: { current: number; pageSize: number }) {\n  await new Promise((resolve) => window.setTimeout(resolve, 200))\n  const total = 24\n  const start = (current - 1) * pageSize\n  return { total, list: Array.from({ length: pageSize }, (_, index) => ({ id: start + index + 1, name: 'Row ' + (start + index + 1) })) }\n}\n\nexport default function UseAntdTableDemo() {\n  const table = useAntdTable(service)\n\n  return (\n    <div>\n      <p><strong>Page:</strong> {table.pagination.current}</p>\n      <ul>{table.tableProps.dataSource.map((row) => <li key={row.id}>{row.name}</li>)}</ul>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => table.pagination.changeCurrent(Math.max(1, table.pagination.current - 1))}>Previous</button>\n        <button type=\"button\" onClick={() => table.pagination.changeCurrent(table.pagination.current + 1)}>Next</button>\n      </div>\n    </div>\n  )\n}\n`,
useFusionTable: `import { useFusionTable } from '@kamod-ch/hooks'\n\nasync function service({ current, pageSize }: { current: number; pageSize: number }) {\n  await new Promise((resolve) => window.setTimeout(resolve, 200))\n  const total = 30\n  const start = (current - 1) * pageSize\n  return { total, list: Array.from({ length: pageSize }, (_, index) => ({ id: start + index + 1, name: 'Fusion row ' + (start + index + 1) })) }\n}\n\nexport default function UseFusionTableDemo() {\n  const table = useFusionTable(service)\n\n  return (\n    <div>\n      <p><strong>Page:</strong> {table.pagination.current}</p>\n      <ul>{table.tableProps.dataSource.map((row) => <li key={row.id}>{row.name}</li>)}</ul>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => table.pagination.changeCurrent(Math.max(1, table.pagination.current - 1))}>Previous</button>\n        <button type=\"button\" onClick={() => table.pagination.changeCurrent(table.pagination.current + 1)}>Next</button>\n      </div>\n    </div>\n  )\n}\n`,
useWebSocket: `import { useEffect, useState } from 'preact/hooks'\nimport { useWebSocket } from '@kamod-ch/hooks'\n\nclass FakeWebSocket extends EventTarget {\n  static CONNECTING = 0\n  static OPEN = 1\n  static CLOSING = 2\n  static CLOSED = 3\n  readyState = 0\n  onopen = null\n  onclose = null\n  onerror = null\n  onmessage = null\n  constructor() {\n    super()\n    window.setTimeout(() => {\n      this.readyState = 1\n      const event = new Event('open')\n      this.dispatchEvent(event)\n      this.onopen?.(event)\n    }, 60)\n  }\n  send(message: string) {\n    window.setTimeout(() => {\n      const event = new MessageEvent('message', { data: 'echo:' + message })\n      this.dispatchEvent(event)\n      this.onmessage?.(event)\n    }, 120)\n  }\n  close() {\n    this.readyState = 3\n    const event = new CloseEvent('close')\n    this.dispatchEvent(event)\n    this.onclose?.(event)\n  }\n}\n\nexport default function UseWebSocketDemo() {\n  const [patched, setPatched] = useState(false)\n\n  useEffect(() => {\n    const Original = window.WebSocket\n    window.WebSocket = FakeWebSocket as unknown as typeof WebSocket\n    setPatched(true)\n    return () => { window.WebSocket = Original }\n  }, [])\n\n  const socket = useWebSocket('ws://simulated-kamod-hooks', { manual: !patched })\n\n  return (\n    <div>\n      <p><strong>Transport:</strong> simulated in-browser WebSocket for the static docs build</p>\n      <p><strong>Ready state:</strong> {socket.readyState}</p>\n      <p><strong>Latest message:</strong> {socket.latestMessage?.data ?? 'none'}</p>\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => socket.connect()}>Connect</button>\n        <button type=\"button\" onClick={() => socket.sendMessage('hello')}>Send hello</button>\n        <button type=\"button\" onClick={() => socket.disconnect()}>Disconnect</button>\n      </div>\n    </div>\n  )\n}\n`,
useWhyDidYouUpdate: `import { useEffect, useState } from 'preact/hooks'\nimport { useWhyDidYouUpdate } from '@kamod-ch/hooks'\n\nfunction Child(props: { count: number; label: string }) {\n  useWhyDidYouUpdate('WhyDidYouUpdateDemo', props)\n  return <pre>{JSON.stringify(props, null, 2)}</pre>\n}\n\nexport default function UseWhyDidYouUpdateDemo() {\n  const [count, setCount] = useState(0)\n  const [label, setLabel] = useState('draft')\n  const [logs, setLogs] = useState<string[]>([])\n\n  useEffect(() => {\n    const original = console.log\n    console.log = (...args) => {\n      if (args[0] === '[why-did-you-update]') {\n        setLogs((value) => [JSON.stringify(args.slice(1)), ...value].slice(0, 3))\n      }\n      original(...args)\n    }\n    return () => {\n      console.log = original\n    }\n  }, [])\n\n  return (\n    <div>\n      <Child count={count} label={label} />\n      <div class=\"demo-actions\">\n        <button type=\"button\" onClick={() => setCount((value) => value + 1)}>Change count</button>\n        <button type=\"button\" onClick={() => setLabel((value) => value === 'draft' ? 'published' : 'draft')}>Change label</button>\n      </div>\n      <pre>{logs.join('\\n') || 'No console log captured yet.'}</pre>\n    </div>\n  )\n}\n`,
useIsomorphicLayoutEffect: `import { useState } from 'preact/hooks'\nimport { useIsomorphicLayoutEffect } from '@kamod-ch/hooks'\n\nexport default function UseIsomorphicLayoutEffectDemo() {\n  const [width, setWidth] = useState(0)\n  useIsomorphicLayoutEffect(() => {\n    setWidth(window.innerWidth)\n  }, [])\n  return <p><strong>Measured width after mount:</strong> {width}</p>\n}\n`,
  }
  return demos[name]
}

for (const meta of metas) {
  const fileBase = path.join(root, 'demos', meta.slug)
  const componentName = `${meta.name}Demo`
  const source = demoSource(meta.name)
  if (!source) throw new Error(`Missing demo for ${meta.name}`)
  write(path.join(fileBase, `${componentName}.tsx`), source)

  const page = `---\ntitle: ${meta.name}\ndescription: ${meta.description}\n---\n\nimport { HookDoc } from '../components/HookDoc'\nimport Demo from '../demos/${meta.slug}/${componentName}'\nimport source from '../demos/${meta.slug}/${componentName}.tsx?raw'\nimport { signatures } from '../generated/hookData'\n\n<HookDoc\n  name=\"${meta.name}\"\n  description=\"${meta.description}\"\n  importCode={\`${meta.importCode}\`}\n  signature={signatures.${meta.name}}\n  source={source}\n  browserOnly={${meta.browserOnly}}\n  related={${JSON.stringify(meta.related)}}\n  ssr={${JSON.stringify(meta.browserOnly ? 'This hook touches browser APIs. Render it after mount or guard it with BrowserOnly in SSR and static builds.' : 'This hook is safe to import during SSR. If your effect body touches the DOM, keep that work inside the effect callback.' )}}\n  browser={${JSON.stringify(meta.browserOnly ? 'Requires the corresponding browser API to exist in the current environment.' : 'Works in any modern browser supported by Preact.')}}\n>\n  <Demo />\n</HookDoc>\n`
  write(path.join(root, 'hooks', `${meta.slug}.mdx`), page)
}

write(path.join(root, 'generated', 'hookData.ts'), `export const signatures = ${JSON.stringify(Object.fromEntries(metas.map((meta) => [meta.name, meta.signature])), null, 2)} as const\n`)

const hookIndex = `---\ntitle: Hooks\ndescription: Complete reference for every public hook export in @kamod-ch/hooks.\n---\n\nimport { DocsLink } from '../components/DocsLink'\n\n## Alphabetical overview\n\n<ul>\n${metas.map((meta) => `  <li><DocsLink href="/hooks/${meta.slug}">${meta.name}</DocsLink> — ${meta.description}</li>`).join('\n')}\n</ul>\n\n${groups.map((group) => `## ${group.text}\n\n<ul>\n${group.items.map((name) => { const meta = metas.find((item) => item.name === name); return `  <li><DocsLink href="/hooks/${meta.slug}">${name}</DocsLink> — ${meta.description}</li>` }).join('\n')}\n</ul>`).join('\n\n')}\n\n## Utilities\n\n<ul>\n${utilities.map((utility) => `  <li><DocsLink href="/utilities/${utility.page}">${utility.name}</DocsLink> — ${utility.description}</li>`).join('\n')}\n</ul>\n` 
write(path.join(root, 'hooks', 'index.mdx'), hookIndex)

write(path.join(root, 'generated', 'sidebar.ts'), `export const hookSidebar = ${JSON.stringify(groups.map((group) => ({ text: group.text, collapsed: true, items: group.items.map((name) => ({ text: name, link: `/hooks/${slug(name)}` })) })), null, 2)} as const\n`)
